// LLM Demo — exercises anna.llm.complete + anna.agent.session.* surfaces.
//
// This bundle is loaded as a native ES module (`<script src="app.js"
// type="module">`), so it imports the Anna App Runtime SDK directly below.
// Call `.connect()` to do the host handshake and obtain the `anna` instance
// that has .llm / .agent / etc.

import { AnnaAppRuntime } from "/static/anna-apps/_sdk/latest/index.js";

// Resolve the executa tool_id at runtime. `anna-tool-ids.js` (generated by
// `anna-app dev` / `apps publish`) assigns `window.__ANNA_TOOL_IDS__`, mapping
// the bundled handle to the server-minted tool_id. The string literal below is
// only a fallback for mock/offline runs where no sidecar is present.
const EXECUTA_HANDLE = "llm-via-executa";
const EXECUTA_TOOL_ID =
  (typeof window !== "undefined" &&
    window.__ANNA_TOOL_IDS__ &&
    window.__ANNA_TOOL_IDS__[EXECUTA_HANDLE]) ||
  "tool-test-llm-via-executa-12345678";
const EXECUTA_METHOD = "complete";

const MODE_HINTS = {
  direct:
    "Calls the host LLM directly from the iframe (anna.llm.complete).",
  executa:
    "Invokes the Executa, which then asks the host to sample (sampling/createMessage). Requires --real LLM bridge; mock fixtures do not serve reverse sampling.",
};

const $ = (id) => document.getElementById(id);
const out = $("complete-out");
const runOut = $("run-out");
const errBox = $("errors");
const uuidInput = $("session-uuid-input");
const sessionStatus = $("session-uuid-status");
const lifecycleEl = $("session-lifecycle");
const toolsEl = $("session-tools");
const toolsWarnEl = $("tools-warning");
const sessionListEl = $("session-list");
const modeSel = $("llm-mode");
const modeHint = $("mode-hint");
const transportSel = $("session-transport");
const transportHint = $("transport-hint");

const TRANSPORT_HINTS = {
  host: "Calls the host session API directly from the iframe (anna.agent.session.*). 'list' uses the account/app-scoped anna.agent.session.list(); run/cancel/history/delete act on whatever app_session_uuid is in the box — anna.agent.session.attach(uuid) re-binds an existing session (e.g. one picked from list()) without minting a new one.",
  executa:
    "Drives sessions through the bundled Executa: anna.tools.invoke → agent_session(op) → reverse-RPC agent/session.*. Requires --real LLM bridge for run; mock fixtures do not serve reverse sampling.",
};

// Unified session state across both transports.
//   handle  — the AgentSession object (HOST API path only); may be a freshly
//             created one or one returned by anna.agent.session.attach(uuid).
//   runId   — last seen run_id (for cancel)
// The app_session_uuid itself lives in the editable #session-uuid-input box,
// which is the single source of truth so the user can act on ANY session
// (typed in, or picked from a list() result), not just the one just created.
const sess = { handle: null, runId: null };

function currentUuid() {
  return (uuidInput.value || "").trim();
}

// Bootstrap the runtime. All click handlers await `annaReady` so they never
// touch `window.anna` before the handshake completes.
const annaReady = (async () => {
  const anna = await AnnaAppRuntime.connect();
  window.anna = anna;
  return anna;
})().catch((err) => {
  showError("runtime.connect", err);
  throw err;
});

function showError(label, err) {
  const code = (err && (err.code || err.error?.code)) || "unknown";
  const name = (err && (err.name || err.error?.name)) || "";
  const msg = (err && (err.message || err.error?.message)) || String(err);
  // Distinguish a dead session (must recreate) from a lapsed token (the SDK
  // self-heals via refresh, so a retry usually succeeds). Branch on the stable
  // `error.name` string, not the numeric code.
  let hint = "";
  if (name === "APP_SESSION_EXPIRED" || name === "APP_SESSION_REVOKED") {
    hint = " — session is gone; create a new one (delete by uuid still works to free quota).";
  } else if (name === "APP_SESSION_TOKEN_EXPIRED") {
    hint = " — token lapsed; click refresh (or just retry — run/cancel self-heal the token).";
  }
  errBox.textContent = `[${label}] ${name || code}: ${msg}${hint}`;
  errBox.classList.add("err");
}

function clearError() {
  errBox.textContent = "(none)";
}

// Render the session lifecycle metadata (sliding idle deadline + absolute cap)
// returned by create / refresh / list. Accepts a handle OR a plain info object.
function renderLifecycle(info) {
  if (!lifecycleEl) return;
  const i = info || {};
  const exp = i.expires_at || null;
  const max = i.max_lifetime_at || null;
  const idle = i.idle_ttl_seconds ?? null;
  if (!exp && !max && idle == null) {
    lifecycleEl.textContent = "lifecycle: (none)";
    return;
  }
  const parts = [];
  if (exp) parts.push(`idle-expires ${exp}`);
  if (max) parts.push(`hard-cap ${max}`);
  if (idle != null) parts.push(`idle-ttl ${idle}s`);
  lifecycleEl.textContent = `lifecycle: ${parts.join("  ·  ")}`;
}

// ──────────────────────────────────────────────────────────
// Tool surface — runtime-ACCURATE since host 1.1.0-beta.45.
//
// session.create now returns the tools the session can REALLY execute
// (not the manifest-declared advisory list):
//   granted_tools: ["*"]   → inherits the user's host tools (files,
//                            browser, commands…) — side effects are real.
//   granted_tools: [a, b]  → explicit sandbox allow-list.
//   granted_tools: []      → TEXT-ONLY: the agent cannot touch local
//                            files; any "changed_files" the model claims
//                            are hallucinated (forum /t/86).
// The same fields (+ a structured `warnings` list) arrive on the
// `run_meta` frame that now opens every agent-run stream, so the app can
// detect the zero-tools condition per-run even on an attach()'d session.

function showToolsWarning(msg) {
  if (!toolsWarnEl) return;
  toolsWarnEl.textContent = msg;
  toolsWarnEl.hidden = false;
}

function hideToolsWarning() {
  if (!toolsWarnEl) return;
  toolsWarnEl.hidden = true;
  toolsWarnEl.textContent = "";
}

// Render from any object carrying granted_tools / inherit_host_tools:
// a create response, an AgentSession handle, or a run_meta frame.
// Older hosts/SDK handles may omit inherit_host_tools — fall back to the
// "*" sentinel, which the host emits iff the inherit grant is on.
function renderToolSurface(info) {
  if (!toolsEl) return;
  if (!info || !Array.isArray(info.granted_tools)) {
    toolsEl.textContent = "tools: (unknown — run or re-create to find out)";
    hideToolsWarning();
    return;
  }
  const granted = info.granted_tools;
  const inherit = info.inherit_host_tools ?? granted.includes("*");
  if (inherit) {
    toolsEl.textContent =
      "tools: * — inherits the user's host tools; file edits are REAL";
    hideToolsWarning();
  } else if (granted.length) {
    toolsEl.textContent = `tools: ${granted.join(", ")} (sandbox allow-list)`;
    hideToolsWarning();
  } else {
    toolsEl.textContent = "tools: NONE — text-only sandbox";
    showToolsWarning(
      "NO_TOOLS_AVAILABLE: this session resolved ZERO executable tools. " +
        "It can only generate text — it cannot read or write local files, and any " +
        "side effects the model claims (e.g. changed_files) will NOT have happened. " +
        "Ask the user to enable “Let agent sessions use my tools” in the app's " +
        "grants drawer, or use llm.complete for text-only generation."
    );
  }
}

// First frame of every app agent run (host ≥ 1.1.0-beta.45). Carries the
// run's authoritative tool surface + structured warnings. Unknown to older
// hosts — simply absent there, so this is fully backward-compatible.
function handleRunMeta(frame) {
  renderToolSurface(frame);
  const tools = frame.inherit_host_tools
    ? "* (host tools)"
    : (frame.granted_tools || []).join(", ") || "NONE";
  runOut.textContent += `[run_meta] run=${frame.run_id || "?"} submode=${frame.submode || "?"} tools=${tools}\n`;
  for (const w of frame.warnings || []) {
    showToolsWarning(`${w.code}: ${w.message}`);
    runOut.textContent += `⚠️ ${w.code}: ${w.message}\n`;
  }
}

// ──────────────────────────────────────────────────────────
// 1. completion — either anna.llm.complete (direct) or
//    anna.tools.invoke against the llm-via-executa plugin which
//    in turn issues sampling/createMessage to the host.

modeSel?.addEventListener("change", () => {
  modeHint.textContent = MODE_HINTS[modeSel.value] || "";
});

// Collect the editable completion parameters shared by both LLM sources.
// Blank fields return `undefined` and are omitted from the request so the host
// applies its own defaults (e.g. temperature 0.7, the user's saved model).
function readCompletionParams() {
  const num = (id) => {
    const raw = ($(id).value || "").trim();
    if (raw === "") return undefined;
    const n = Number(raw);
    return Number.isFinite(n) ? n : undefined;
  };
  const str = (id) => ($(id).value || "").trim() || undefined;
  const stopRaw = str("cmp-stop");
  const stop = stopRaw
    ? stopRaw.split(",").map((s) => s.trim()).filter(Boolean)
    : undefined;
  return {
    systemPrompt: str("cmp-system"),
    maxTokens: num("cmp-maxtokens") ?? 256,
    temperature: num("cmp-temperature"),
    stop: stop && stop.length ? stop : undefined,
    modelHint: str("cmp-hint"),
    costPriority: num("cmp-cost"),
    speedPriority: num("cmp-speed"),
    intelligencePriority: num("cmp-intel"),
  };
}

// Build an MCP modelPreferences object from the params, or undefined if the
// user left every preference field blank.
function buildModelPreferences(p) {
  const mp = {};
  if (p.modelHint) mp.hints = [{ name: p.modelHint }];
  if (p.costPriority !== undefined) mp.costPriority = p.costPriority;
  if (p.speedPriority !== undefined) mp.speedPriority = p.speedPriority;
  if (p.intelligencePriority !== undefined)
    mp.intelligencePriority = p.intelligencePriority;
  return Object.keys(mp).length ? mp : undefined;
}

async function runDirect(prompt) {
  const anna = await annaReady;
  const p = readCompletionParams();
  const req = {
    messages: [{ role: "user", content: { type: "text", text: prompt } }],
    maxTokens: p.maxTokens,
  };
  if (p.systemPrompt) req.systemPrompt = p.systemPrompt;
  if (p.temperature !== undefined) req.temperature = p.temperature;
  if (p.stop) req.stopSequences = p.stop;
  const modelPreferences = buildModelPreferences(p);
  if (modelPreferences) req.modelPreferences = modelPreferences;
  return anna.llm.complete(req);
}

async function runViaExecuta(prompt) {
  const anna = await annaReady;
  const p = readCompletionParams();
  const args = { prompt, max_tokens: p.maxTokens };
  if (p.systemPrompt) args.system_prompt = p.systemPrompt;
  if (p.temperature !== undefined) args.temperature = p.temperature;
  if (p.stop) args.stop = p.stop;
  if (p.modelHint) args.model_hint = p.modelHint;
  if (p.costPriority !== undefined) args.cost_priority = p.costPriority;
  if (p.speedPriority !== undefined) args.speed_priority = p.speedPriority;
  if (p.intelligencePriority !== undefined)
    args.intelligence_priority = p.intelligencePriority;
  return anna.tools.invoke({
    tool_id: EXECUTA_TOOL_ID,
    method: EXECUTA_METHOD,
    args,
  });
}

$("complete-btn").addEventListener("click", async () => {
  clearError();
  const mode = modeSel?.value || "direct";
  out.textContent = `(calling ${mode === "executa" ? "executa.complete" : "llm.complete"}…)`;
  try {
    const prompt = $("complete-input").value || "hi";
    const reply =
      mode === "executa" ? await runViaExecuta(prompt) : await runDirect(prompt);
    out.textContent = JSON.stringify(reply, null, 2);
  } catch (err) {
    out.textContent = "(failed)";
    showError(mode === "executa" ? "tools.invoke" : "llm.complete", err);
  }
});

// ──────────────────────────────────────────────────────────
// 1b. sample_chain — N sequential sampling/createMessage calls in ONE
//     invoke. Exercises the host max_calls quota and the sampling-token
//     renewal path (forum /t/83): a long enough chain outlives the 10-min
//     token TTL, and the host transparently renews + retries mid-invoke.

const chainOut = $("chain-out");

$("chain-btn").addEventListener("click", async () => {
  clearError();
  const anna = await annaReady;
  const steps = Math.max(1, Number($("chain-steps").value) || 3);
  const delay_s = Math.max(0, Number($("chain-delay").value) || 0);
  const max_tokens = Math.max(1, Number($("chain-maxtokens").value) || 128);
  const prompt = $("chain-input").value || "hi";
  chainOut.textContent = `(running sample_chain: ${steps} step(s)…)`;
  try {
    const reply = await anna.tools.invoke({
      tool_id: EXECUTA_TOOL_ID,
      method: "sample_chain",
      args: { prompt, steps, delay_s, max_tokens },
    });
    chainOut.textContent = JSON.stringify(reply, null, 2);
  } catch (err) {
    chainOut.textContent = "(failed)";
    showError("tools.invoke(sample_chain)", err);
  }
});

// ──────────────────────────────────────────────────────────
// 2. agent.session — full method coverage over two transports.
//
//    HOST API   : anna.agent.session({...}) → AgentSession handle, plus
//                 the account/app-scoped anna.agent.session.list().
//    Reverse RPC: anna.tools.invoke({ method: "agent_session", args: {op} })
//                 against the bundled llm-via-executa plugin, which issues
//                 agent/session.* reverse-RPCs back to the host.

transportSel?.addEventListener("change", () => {
  transportHint.textContent = TRANSPORT_HINTS[transportSel.value] || "";
  // Switching transport invalidates any live session handle and the
  // selected uuid (host vs executa sessions are scoped differently).
  resetSession();
});

function transport() {
  return transportSel?.value || "host";
}

// Enable the per-session actions whenever there's a uuid to act on — whether
// it came from create(), was typed in, or was picked from a list() result.
function syncSessionButtons() {
  const active = currentUuid().length > 0;
  $("run-btn").disabled = !active;
  $("cancel-btn").disabled = !active;
  $("history-btn").disabled = !active;
  $("refresh-btn").disabled = !active;
  $("delete-btn").disabled = !active;
  if (active) {
    sessionStatus.textContent = `session: ${currentUuid()}`;
    sessionStatus.classList.remove("muted");
  } else {
    sessionStatus.textContent = "no session";
    sessionStatus.classList.add("muted");
  }
  highlightActiveListItem();
}

// Keep the highlighted list entry in sync with the input.
function highlightActiveListItem() {
  const uuid = currentUuid();
  for (const b of sessionListEl.querySelectorAll("button")) {
    b.classList.toggle("active", b.dataset.uuid === uuid);
  }
}

// The uuid box is the source of truth; typing re-evaluates button state and
// drops any stale handle that no longer matches.
uuidInput?.addEventListener("input", () => {
  if (sess.handle && sess.handle.app_session_uuid !== currentUuid()) {
    sess.handle = null;
    sess.runId = null;
    // A foreign uuid's tool surface is unknown until the next run_meta.
    renderToolSurface(null);
  }
  syncSessionButtons();
});

function setUuid(uuid) {
  uuidInput.value = uuid || "";
  syncSessionButtons();
}

function resetSession() {
  sess.handle = null;
  sess.runId = null;
  uuidInput.value = "";
  sessionListEl.replaceChildren();
  renderLifecycle(null);
  renderToolSurface(null);
  syncSessionButtons();
}

// HOST API: resolve an AgentSession handle for the uuid currently in the box.
// Reuses the freshly-created handle when it matches; otherwise re-binds an
// existing session via the SDK's client-side attach() (no RPC, no new session).
async function hostHandle() {
  const anna = await annaReady;
  const uuid = currentUuid();
  if (sess.handle && sess.handle.app_session_uuid === uuid) return sess.handle;
  sess.handle = anna.agent.session.attach(uuid);
  return sess.handle;
}

// Reverse RPC helper: invoke the bundled plugin's agent_session tool.
async function executaSession(op, args = {}) {
  const anna = await annaReady;
  const reply = await anna.tools.invoke({
    tool_id: EXECUTA_TOOL_ID,
    method: "agent_session",
    args: { op, ...args },
  });
  // tools.invoke unwraps to the tool's `data` payload.
  return reply;
}

$("session-create-btn").addEventListener("click", async () => {
  clearError();
  try {
    const anna = await annaReady;
    const systemPrompt = ($("session-system-prompt").value || "").trim() || undefined;
    let uuid;
    if (transport() === "host") {
      sess.handle = await anna.agent.session({ submode: "auto", system_prompt: systemPrompt });
      uuid = sess.handle.app_session_uuid || null;
      // The handle carries lifecycle metadata (expires_at / max_lifetime_at /
      // idle_ttl_seconds) straight off the create response, plus the
      // runtime-accurate granted_tools — check it BEFORE running anything
      // that's supposed to have side effects.
      renderLifecycle(sess.handle);
      renderToolSurface(sess.handle);
    } else {
      const r = await executaSession("create", { submode: "auto", system_prompt: systemPrompt });
      sess.handle = null;
      uuid = r.app_session_uuid || null;
      renderLifecycle(r);
      renderToolSurface(r);
    }
    setUuid(uuid || "");
  } catch (err) {
    showError("agent.session.create", err);
  }
});

$("run-btn").addEventListener("click", async () => {
  clearError();
  const uuid = currentUuid();
  if (!uuid) return;
  const content = $("run-input").value || "hello";
  runOut.textContent = "(streaming…)\n";
  try {
    if (transport() === "host") {
      // attach() (or the fresh create handle) gives a streaming .run() for
      // ANY existing uuid — e.g. one picked from a list() result after reload.
      const handle = await hostHandle();
      const stream = handle.run({ content });
      for await (const frame of stream) {
        if (frame.run_id) sess.runId = frame.run_id;
        if (frame.event === "run_meta") {
          // Authoritative tool surface for THIS run (and zero-tools warning).
          handleRunMeta(frame);
        } else if (frame.event === "token" && frame.text) {
          runOut.textContent += frame.text;
        } else {
          runOut.textContent += `\n[${frame.event}] ${JSON.stringify(frame)}\n`;
        }
      }
      // The stream carries the host-assigned run_id (used by cancel).
      if (stream.runId) sess.runId = stream.runId;
      runOut.textContent += "\n(done)";
    } else {
      const r = await executaSession("run", {
        app_session_uuid: uuid,
        prompt: content,
      });
      runOut.textContent = (r.text || JSON.stringify(r, null, 2)) + "\n";
      // The reverse-RPC run is buffered — the run_meta frame (tool surface +
      // NO_TOOLS_AVAILABLE warning) is in the returned frames array.
      for (const frame of r.frames || []) {
        if (frame.run_id) sess.runId = frame.run_id;
        if (frame.event === "run_meta") handleRunMeta(frame);
      }
    }
  } catch (err) {
    showError("agent.session.run", err);
  }
});

$("cancel-btn").addEventListener("click", async () => {
  clearError();
  const uuid = currentUuid();
  if (!uuid) return;
  try {
    let res;
    if (transport() === "host") {
      const handle = await hostHandle();
      res = await handle.cancel(sess.runId || undefined);
    } else {
      res = await executaSession("cancel", {
        app_session_uuid: uuid,
        run_id: sess.runId || "",
      });
    }
    runOut.textContent = JSON.stringify(res, null, 2);
  } catch (err) {
    showError("agent.session.cancel", err);
  }
});

$("history-btn").addEventListener("click", async () => {
  clearError();
  const uuid = currentUuid();
  if (!uuid) return;
  try {
    let h;
    if (transport() === "host") {
      const handle = await hostHandle();
      h = await handle.history();
    } else {
      h = await executaSession("history", { app_session_uuid: uuid });
    }
    runOut.textContent = JSON.stringify(h, null, 2);
  } catch (err) {
    showError("agent.session.history", err);
  }
});

// refresh: re-mint the short-lived token AND slide the idle window for an
// EXISTING session, identified only by its app_session_uuid. This is how a
// session survives long idle gaps, an iframe reload, or a host restart — no
// live token required. Works on any uuid in the box (created, typed, or
// picked from list()). The HOST handle's .refresh() also updates its
// in-memory lifecycle fields; both transports echo fresh deadlines.
$("refresh-btn").addEventListener("click", async () => {
  clearError();
  const uuid = currentUuid();
  if (!uuid) return;
  try {
    let r;
    if (transport() === "host") {
      const handle = await hostHandle();
      r = await handle.refresh();
      // handle.refresh() copies the new deadlines onto the handle in place.
      renderLifecycle(handle);
    } else {
      r = await executaSession("refresh", { app_session_uuid: uuid });
      renderLifecycle(r);
    }
    runOut.textContent = JSON.stringify(r, null, 2);
  } catch (err) {
    showError("agent.session.refresh", err);
  }
});

$("delete-btn").addEventListener("click", async () => {
  clearError();
  const uuid = currentUuid();
  if (!uuid) return;
  try {
    if (transport() === "host") {
      const handle = await hostHandle();
      await handle.delete();
    } else {
      await executaSession("delete", { app_session_uuid: uuid });
    }
    resetSession();
    runOut.textContent = "(session deleted)";
  } catch (err) {
    showError("agent.session.delete", err);
  }
});

// Render list() results as clickable chips that load the uuid into the box.
function renderSessionList(sessions) {
  sessionListEl.replaceChildren();
  for (const s of sessions) {
    const uuid = s.app_session_uuid || s.uuid;
    if (!uuid) continue;
    const btn = document.createElement("button");
    btn.type = "button";
    btn.dataset.uuid = uuid;
    const tail = uuid.length > 14 ? `…${uuid.slice(-10)}` : uuid;
    btn.textContent = s.label ? `${s.label} (${tail})` : tail;
    btn.title = uuid;
    btn.addEventListener("click", () => {
      // Picking an existing session drops any stale handle; host actions
      // will attach() to this uuid on demand. Show the row's lifecycle so the
      // user can see how close it is to its idle/hard deadline before acting.
      sess.handle = null;
      sess.runId = null;
      setUuid(uuid);
      renderLifecycle(s);
    });
    sessionListEl.appendChild(btn);
  }
  highlightActiveListItem();
}

$("list-btn").addEventListener("click", async () => {
  clearError();
  runOut.textContent = "(listing…)";
  try {
    const anna = await annaReady;
    let sessions;
    if (transport() === "host") {
      // Account/app-scoped raw RPC — lives on the namespace, not a handle.
      const r = await anna.agent.session.list({ include_expired: false, limit: 50 });
      sessions = (r && r.sessions) || r || [];
    } else {
      const r = await executaSession("list", { include_expired: false, limit: 50 });
      sessions = r.sessions || [];
    }
    renderSessionList(sessions);
    runOut.textContent = JSON.stringify(sessions, null, 2);
  } catch (err) {
    showError("agent.session.list", err);
  }
});

// ──────────────────────────────────────────────────────────
// Init hint text to match the default selections.
if (modeHint) modeHint.textContent = MODE_HINTS[modeSel?.value || "direct"] || "";
if (transportHint)
  transportHint.textContent = TRANSPORT_HINTS[transportSel?.value || "host"] || "";
// Reflect the (empty) uuid box into button/disabled state on load.
syncSessionButtons();
